360			if !already {
361				domains = append(domains, domain)
362				if err := setSearchDomains(service, domains); err != nil {
363					return err
364				}
365			}
366			rememberSearchDomain(state, service, domain, !already)
367		}
368		return saveDNSState(state)
369	}
