371	func removeSearchDomain(domain string) error {
372		state, err := loadDNSState()
373		if err != nil {
374			return err
375		}
376		services, err := targetServices()
377		if err != nil {
378			return err
379		}
380		for _, service := range services {
381			managed, ok := state.Search[service][domain]
382			if !ok || !managed.AddedBySandcastle {
383				continue
384			}
385			domains, err := getSearchDomains(service)
386			if err != nil {
387				return err
388			}
389			next := removeDomain(domains, domain)
390			if err := setSearchDomains(service, next); err != nil {
391				return err
392			}
393			delete(state.Search[service], domain)
394		}
395		return saveDNSState(state)
396	}
