413		if err != nil {
414			return nil, err
415		}
416		if dnsSearchAll {
417			return services, nil
418		}
419		if len(services) == 0 {
420			return nil, fmt.Errorf("no enabled macOS network services found")
421		}
422		return []string{services[0]}, nil
