425	func listNetworkServices() ([]string, error) {
426		ordered, err := listNetworkServiceOrder()
427		if err == nil && len(ordered) > 0 {
428			return ordered, nil
429		}
430	
431		out, err := exec.Command("/usr/sbin/networksetup", "-listallnetworkservices").Output()
432		if err != nil {
433			return nil, err
434		}
435		lines := strings.Split(string(out), "\n")
436		var services []string
437		for _, line := range lines {
438			line = strings.TrimSpace(line)
439			if line == "" || strings.HasPrefix(line, "An asterisk") || strings.HasPrefix(line, "*") {
440				continue
441			}
442			services = append(services, line)
443		}
444		return services, nil
445	}
