447	func listNetworkServiceOrder() ([]string, error) {
448		out, err := exec.Command("/usr/sbin/networksetup", "-listnetworkserviceorder").Output()
449		if err != nil {
450			return nil, err
451		}
452		lines := strings.Split(string(out), "\n")
453		var services []string
454		for _, line := range lines {
455			line = strings.TrimSpace(line)
456			if !strings.HasPrefix(line, "(") {
457				continue
458			}
459			end := strings.Index(line, ") ")
460			if end < 0 || end+2 >= len(line) {
461				continue
462			}
463			name := strings.TrimSpace(line[end+2:])
464			if name == "" || strings.HasPrefix(name, "*") || strings.HasPrefix(name, "Hardware Port:") {
465				continue
466			}
467			services = append(services, name)
468		}
469		return services, nil
470	}
