472	func getSearchDomains(service string) ([]string, error) {
473		out, err := exec.Command("/usr/sbin/networksetup", "-getsearchdomains", service).Output()
474		if err != nil {
475			return nil, err
476		}
477		text := strings.TrimSpace(string(out))
478		if text == "" || strings.Contains(text, "There aren't any Search Domains") {
479			return nil, nil
480		}
481		return strings.Fields(text), nil
482	}
