484	func setSearchDomains(service string, domains []string) error {
485		args := []string{"/usr/sbin/networksetup", "-setsearchdomains", service}
486		if len(domains) == 0 {
487			args = append(args, "Empty")
488		} else {
489			args = append(args, domains...)
490		}
491		fmt.Printf("Running: sudo %s\n", strings.Join(shellQuote(args), " "))
492		return run("sudo", args...)
493	}
