495	func loadDNSState() (*dnsState, error) {
496		state := &dnsState{Search: make(map[string]map[string]managedSearchDomain)}
497		data, err := os.ReadFile(dnsStatePath())
498		if err != nil {
499			if os.IsNotExist(err) {
500				return state, nil
501			}
502			return nil, err
503		}
504		if err := yaml.Unmarshal(data, state); err != nil {
505			return nil, err
506		}
507		if state.Search == nil {
508			state.Search = make(map[string]map[string]managedSearchDomain)
509		}
510		return state, nil
511	}
512	
513	func saveDNSState(state *dnsState) error {
514		if err := os.MkdirAll(config.Dir(), 0o700); err != nil {
515			return err
516		}
517		data, err := yaml.Marshal(state)
518		if err != nil {
519			return err
520		}
521		return os.WriteFile(dnsStatePath(), data, 0o600)
522	}
523	
524	func dnsStatePath() string {
525		return filepath.Join(config.Dir(), "dns.yaml")
526	}
527	
528	func contains(items []string, target string) bool {
529		for _, item := range items {
530			if item == target {
531				return true
532			}
533		}
534		return false
535	}
536	
537	func removeDomain(items []string, target string) []string {
538		out := make([]string, 0, len(items))
539		for _, item := range items {
540			if item != target {
541				out = append(out, item)
542			}
543		}
