// ---------- views ----------

type tuiView int

const (
	viewSandboxes tuiView = iota
	viewRoutes
	viewCreateSandbox
	viewCreateProject
	viewAddRoute
	viewConfirmDelete
	viewServers
	viewAddServer
	viewServerLogin
	viewConfirmRemoveServer
	viewSettings
)

// ---------- form field types ----------

type fieldKind int

const (
	fieldText fieldKind = iota
	fieldBool
	fieldCycle
)

type formField struct {
	label        string
	kind         fieldKind
	input        textinput.Model // for fieldText
	boolVal      bool            // for fieldBool
	defBool      bool            // default value (to show as dimmed when matching)
	cycleOptions []string        // for fieldCycle
	cycleIdx     int             // for fieldCycle — current selection
}

// ---------- messages ----------

type sandboxesLoadedMsg struct {
	sandboxes []api.Sandbox
	err       error
}

type routesLoadedMsg struct {
	routes []api.RouteResponse
	err    error
}

type dnsLoadedMsg struct {
	names map[int]string
}

type snapshotsLoadedMsg struct {
	snapshots []api.Snapshot
	err       error
}

type actionDoneMsg struct {
	msg string
	err error
}

type deviceCodeMsg struct {
	code *api.DeviceCodeResponse
	err  error
}

type deviceTokenMsg struct {
	token   string
	pending bool
	err     error
}

// ---------- model ----------

type tuiModel struct {
	client *api.Client

	view     tuiView
	cursor   int
	width    int
	height   int
	spinner  spinner.Model
	loading  bool
	feedback string
	feedErr  bool

	// sandbox list
	sandboxes []api.Sandbox
	dnsNames  map[int]string

	// routes
	routeSandbox *api.Sandbox
	routes       []api.RouteResponse
	routeCursor  int

	// create sandbox form
	createFields []formField
	createCursor int
	snapshots    []api.Snapshot // cached for snapshot name completion

	// create project form
	projectFields []formField
	projectCursor int

	// add route
	routeInputs   [2]textinput.Model // domain, port
	routeFocusIdx int

	// confirm delete
	deleteTarget string
	deleteID     int

	// server management
	servers           []serverEntry
	serverCursor      int
	addServerInputs   [2]textinput.Model // URL, alias
	addServerFocus    int
	addServerInsecure bool

	// device auth login
	loginAlias      string
	loginURL        string
	loginInsecure   bool
	loginClient     *api.Client
	loginDeviceCode *api.DeviceCodeResponse
	loginPolling    bool
	loginUserCode   string
	loginVerifyURL  string

	// confirm remove server
	removeServerAlias string

	// settings
	settingsFields []formField
	settingsCursor int
}

type serverEntry struct {
	alias    string
	url      string
	active   bool
	hasToken bool
}

func makeTextInput(placeholder string, width int) textinput.Model {
	ti := textinput.New()
	ti.Placeholder = placeholder
	ti.CharLimit = 80
	ti.Width = width
	return ti

